      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "completion_tokens"), env.opts.autoescape);
      output += "</div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n\r\n            <footer class=\"footer\">\r\n                <div class=\"footer-left\">\r\n                    <strong>ATRI Theme · Daily Report</strong><br>\r\n                    亚托莉会永远把大家珍贵的聊天记忆藏在海底哦。\r\n                </div>\r\n                <div class=\"footer-author\" style=\"margin-left: auto; display: flex; align-items: center; gap: 6px; font-family: 'LXGW WenKai Mono', monospace; font-weight: 600; color: var(--deep); opacity: 0.8;\">\r\n                    <svg class=\"icon-svg\" style=\"width: 14px; height: 14px; fill: var(--deep);\">\r\n                        <use href=\"#icon-heart\"></use>\r\n                    </svg>\r\n                    <span>Template by Liangyu-G</span>\r\n                </div>\r\n            </footer>\r\n        </div>\r\n    </div>\r\n\r\n    <script>\r\n    /* ==========================================\r\n       NUMBER COUNTER ANIMATION\r\n    ========================================== */\r\n    (function () {\r\n        function animateCount(el, target, duration) {\r\n            const start = performance.now();\r\n            const startVal = 0;\r\n            function step(now) {\r\n                const elapsed = now - start;\r\n                const progress = Math.min(elapsed / duration, 1);\r\n                // Ease out cubic\r\n                const ease = 1 - Math.pow(1 - progress, 3);\r\n                const current = Math.round(startVal + (target - startVal) * ease);\r\n                el.textContent = current.toLocaleString();\r\n                if (progress < 1) requestAnimationFrame(step);\r\n            }\r\n            requestAnimationFrame(step);\r\n        }\r\n\r\n        function tryAnimate() {\r\n            // Stat values\r\n            document.querySelectorAll('.stat-value').forEach(el => {\r\n                const raw = el.textContent.trim().replace(/,/g, '');\r\n                const num = parseFloat(raw);\r\n                if (!isNaN(num) && num > 0) animateCount(el, num, 1200);\r\n            });\r\n            // Token values\r\n            document.querySelectorAll('.token-value').forEach(el => {\r\n                const raw = el.textContent.trim().replace(/,/g, '');\r\n                const num = parseFloat(raw);\r\n                if (!isNaN(num) && num > 0) animateCount(el, num, 1600);\r\n            });\r\n        }\r\n\r\n        // Run after a short delay to let the page paint\r\n        setTimeout(tryAnimate, 400);\r\n    })();\r\n\r\n    /* ==========================================\r\n       ENTRANCE RIPPLE ON SECTION CLICK\r\n    ========================================== */\r\n    document.querySelectorAll('.section, .stat-card, .token-card').forEach(el => {\r\n        el.addEventListener('click', function (e) {\r\n            const rect = el.getBoundingClientRect();\r\n            const rippleX = e.clientX - rect.left;\r\n            const rippleY = e.clientY - rect.top;\r\n            const ripple = document.createElement('span');\r\n            ripple.className = 'click-kawaii-burst';\r\n            ripple.style.left = `${rippleX}px`;\r\n            ripple.style.top = `${rippleY}px`;\r\n            ripple.innerHTML = `\r\n                <span class=\"burst-core\"></span>\r\n                <span class=\"burst-ring\"></span>\r\n                <span class=\"burst-sparkle sparkle-1\"></span>\r\n                <span class=\"burst-sparkle sparkle-2\"></span>\r\n                <span class=\"burst-sparkle sparkle-3\"></span>\r\n                <span class=\"burst-heart\"></span>\r\n            `;\r\n            el.style.position = 'relative';\r\n            el.style.overflow = 'hidden';\r\n            el.appendChild(ripple);\r\n            setTimeout(() => ripple.remove(), 900);\r\n        });\r\n    });\r\n    // Inject ripple keyframe dynamically\r\n    const styleEl = document.createElement('style');\r\n    styleEl.textContent = `\r\n    .click-kawaii-burst {\r\n        position: absolute;\r\n        width: 0;\r\n        height: 0;\r\n        pointer-events: none;\r\n        z-index: 30;\r\n    }\r\n    .click-kawaii-burst > span {\r\n        position: absolute;\r\n        left: 0;\r\n        top: 0;\r\n        transform: translate(-50%, -50%);\r\n        pointer-events: none;\r\n    }\r\n    .click-kawaii-burst .burst-core {\r\n        width: 18px;\r\n        height: 18px;\r\n        border-radius: 999px;\r\n        background: radial-gradient(circle, rgba(255,255,255,0.98) 0%, rgba(255,214,242,0.95) 42%, rgba(156,220,255,0.86) 100%);\r\n        box-shadow: 0 0 0 6px rgba(255,255,255,0.18), 0 0 18px rgba(151, 222, 255, 0.45);\r\n        animation: kawaiiPop 0.72s ease-out forwards;\r\n    }\r\n    .click-kawaii-burst .burst-ring {\r\n        width: 22px;\r\n        height: 22px;\r\n        border-radius: 999px;\r\n        border: 2px solid rgba(255,255,255,0.9);\r\n        box-shadow: 0 0 0 1px rgba(154, 219, 255, 0.28) inset;\r\n        animation: kawaiiRing 0.78s ease-out forwards;\r\n    }\r\n    .click-kawaii-burst .burst-sparkle {\r\n        width: 10px;\r\n        height: 10px;\r\n        border-radius: 3px;\r\n        transform: translate(-50%, -50%) rotate(45deg);\r\n        background: linear-gradient(135deg, #fff7b8, #ffd8f3);\r\n        box-shadow: 0 0 10px rgba(255, 214, 120, 0.35);\r\n    }\r\n    .click-kawaii-burst .sparkle-1 { animation: sparkleOne 0.82s ease-out forwards; }\r\n    .click-kawaii-burst .sparkle-2 { animation: sparkleTwo 0.82s ease-out forwards; }\r\n    .click-kawaii-burst .sparkle-3 { animation: sparkleThree 0.82s ease-out forwards; }\r\n    .click-kawaii-burst .burst-heart {\r\n        width: 12px;\r\n        height: 12px;\r\n        background: linear-gradient(135deg, #ffb7df, #ffc9a8);\r\n        transform: translate(-50%, -50%) rotate(-45deg);\r\n        border-radius: 3px 3px 1px 1px;\r\n        box-shadow: 0 0 12px rgba(255, 170, 214, 0.38);\r\n        animation: heartFloat 0.9s ease-out forwards;\r\n    }\r\n    .click-kawaii-burst .burst-heart::before,\r\n    .click-kawaii-burst .burst-heart::after {\r\n        content: \"\";\r\n        position: absolute;\r\n        width: 12px;\r\n        height: 12px;\r\n        border-radius: 50%;\r\n        background: inherit;\r\n    }\r\n    .click-kawaii-burst .burst-heart::before {\r\n        left: 0;\r\n        top: -6px;\r\n    }\r\n    .click-kawaii-burst .burst-heart::after {\r\n        left: 6px;\r\n        top: 0;\r\n    }\r\n    @keyframes kawaiiPop {\r\n        0% { opacity: 0.95; transform: translate(-50%, -50%) scale(0.2); }\r\n        65% { opacity: 0.9; transform: translate(-50%, -50%) scale(1.5); }\r\n        100% { opacity: 0; transform: translate(-50%, -50%) scale(2.2); }\r\n    }\r\n    @keyframes kawaiiRing {\r\n        0% { opacity: 0.8; transform: translate(-50%, -50%) scale(0.3); }\r\n        100% { opacity: 0; transform: translate(-50%, -50%) scale(4.8); }\r\n    }\r\n    @keyframes sparkleOne {\r\n        0% { opacity: 0; transform: translate(-50%, -50%) rotate(45deg) scale(0.2); }\r\n        35% { opacity: 1; }\r\n        100% { opacity: 0; transform: translate(calc(-50% - 24px), calc(-50% - 28px)) rotate(120deg) scale(1.15); }\r\n    }\r\n    @keyframes sparkleTwo {\r\n        0% { opacity: 0; transform: translate(-50%, -50%) rotate(45deg) scale(0.2); }\r\n        35% { opacity: 1; }\r\n        100% { opacity: 0; transform: translate(calc(-50% + 28px), calc(-50% - 16px)) rotate(160deg) scale(1.05); }\r\n    }\r\n    @keyframes sparkleThree {\r\n        0% { opacity: 0; transform: translate(-50%, -50%) rotate(45deg) scale(0.2); }\r\n        35% { opacity: 1; }\r\n        100% { opacity: 0; transform: translate(calc(-50% + 12px), calc(-50% + 26px)) rotate(135deg) scale(0.95); }\r\n    }\r\n    @keyframes heartFloat {\r\n        0% { opacity: 0; transform: translate(-50%, -50%) rotate(-45deg) scale(0.2); }\r\n        25% { opacity: 1; }\r\n        100% { opacity: 0; transform: translate(calc(-50% - 18px), calc(-50% - 34px)) rotate(-25deg) scale(1.05); }\r\n    }`;\r\n    document.head.appendChild(styleEl);\r\n    </script>\r\n</body>\r\n\r\n</html>";
