      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "message_count"), env.opts.autoescape);
      output += "</div>\n                <div class=\"stat-note\">累计消息数量</div>\n            </div>\n\n            <div class=\"stat-box\">\n                <span class=\"stat-label\">Participants</span>\n                <div class=\"stat-value\">";
