      output += "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>五彩斑斓的一天，来看看群里发生了什么吧！ · ";
      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "current_date"), env.opts.autoescape);
      output += "</title>\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <!-- 引入手写字体和正文阅读字体 -->\n    <link\n        href=\"https://fonts.googleapis.com/css2?family=ZCOOL+KuaiLe&family=Long+Cang&family=Noto+Sans+SC:wght@400;500;700&family=Patrick+Hand&display=swap\"\n        rel=\"stylesheet\">\n\n    <style>\n        :root {\n            --bg-paper: #fdfbf7;\n            --ink-primary: #5d4037;\n            --ink-secondary: #8d6e63;\n            --color-yellow: #fff9c4;\n            --color-pink: #ffccbc;\n            --color-blue: #b3e5fc;\n            --color-green: #c8e6c9;\n            --color-purple: #e1bee7;\n            --accent-orange: #ff7043;\n            --mbti-bg: #ede7f6;\n            --mbti-border: #9575cd;\n            --mbti-text: #512da8;\n            --title-bg: #fffde7;\n            --title-border: #ffb74d;\n            --title-text: #bf360c;\n\n            --font-title: 'ZCOOL KuaiLe', cursive;\n            --font-hand: 'Patrick Hand', \"KaiTi\", \"STKaiti\", serif;\n            --font-body: 'Noto Sans SC', sans-serif;\n        }\n\n        @page {\n            size: A4;\n            margin: 0;\n        }\n\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n\n        body {\n            font-family: var(--font-body);\n            color: var(--ink-primary);\n            background-color: var(--bg-paper);\n            background-image: radial-gradient(#ddd 1px, transparent 1px);\n            padding: 20mm;\n            line-height: 1.5;\n            font-size: 12px;\n        }\n\n        .doodle {\n            width: 20px;\n            height: 20px;\n            fill: currentColor;\n            display: inline-block;\n            vertical-align: middle;\n            flex-shrink: 0;\n        }\n\n        .container {\n            width: 100%;\n            max-width: 180mm;\n            margin: 0 auto;\n            position: relative;\n            background: #fff;\n            border: 2px solid var(--ink-primary);\n            border-radius: 12px;\n            padding: 30px;\n            box-shadow: 6px 6px 0 var(--color-blue), 12px 12px 0 var(--color-pink);\n        }\n\n        /* Stitching Effect */\n        .container::before {\n            content: \"\";\n            position: absolute;\n            top: 10px;\n            bottom: 10px;\n            left: 10px;\n            right: 10px;\n            border: 1.5px dashed rgba(93, 64, 55, 0.2);\n            border-radius: 10px;\n            pointer-events: none;\n        }\n\n        /* ==================== 1. Header ==================== */\n        .header {\n            text-align: center;\n            margin-bottom: 25px;\n            position: relative;\n        }\n\n        .title-sticker {\n            display: inline-block;\n            background: #fff;\n            padding: 10px 40px;\n            border: 2px dashed var(--ink-primary);\n            border-radius: 10px;\n            box-shadow: 3px 3px 0 var(--color-blue);\n            transform: rotate(-0.5deg);\n            position: relative;\n        }\n\n        .title-sticker h1 {\n            font-family: var(--font-title);\n            font-size: 1.8rem;\n            color: var(--accent-orange);\n            margin: 0;\n        }\n\n        .date-badge {\n            position: absolute;\n            bottom: -10px;\n            right: -10px;\n            background: var(--color-yellow);\n            padding: 4px 12px;\n            font-family: var(--font-hand);\n            font-size: 1rem;\n            border: 1px solid var(--ink-primary);\n            transform: rotate(2deg);\n            z-index: 5;\n        }\n\n        .tape {\n            position: absolute;\n            top: -10px;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 100px;\n            height: 20px;\n            background: rgba(255, 171, 145, 0.7);\n            opacity: 0.8;\n            mask-image: radial-gradient(circle at 5px, transparent 4px, black 5px);\n            mask-size: 10px 100%;\n            mask-repeat: repeat-x;\n        }\n\n        /* ==================== 2. Stats & Highlights ==================== */\n        .stats-wrapper {\n            display: flex;\n            gap: 20px;\n            margin-bottom: 25px;\n            align-items: stretch;\n        }\n\n        .stats-grid {\n            flex: 1.2;\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 10px;\n        }\n\n        .stamp {\n            background: #fff;\n            padding: 8px;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 8px;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            height: 70px;\n            position: relative;\n            box-shadow: 2px 2px 0 rgba(0, 0, 0, 0.1);\n        }\n\n        /* Decorative background texture */\n        .stamp::after {\n            content: \"\";\n            position: absolute;\n            top: 5px;\n            bottom: 5px;\n            left: 5px;\n            right: 5px;\n            border: 1px dashed rgba(93, 64, 55, 0.1);\n            border-radius: 8px;\n            pointer-events: none;\n        }\n\n        .stamp-num {\n            font-family: var(--font-title);\n            font-size: 1.3rem;\n            color: var(--accent-orange);\n            line-height: 1;\n            margin: 2px 0;\n        }\n\n        .stamp-label {\n            font-family: var(--font-hand);\n            font-size: 0.8rem;\n            color: var(--ink-secondary);\n        }\n\n        .highlight-section {\n            flex: 1;\n            background: var(--color-yellow);\n            padding: 15px;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 10px;\n            box-shadow: 4px 4px 0 var(--color-pink);\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            text-align: center;\n            position: relative;\n            background-image: repeating-linear-gradient(45deg, rgba(255, 255, 255, 0.3) 0, rgba(255, 255, 255, 0.3) 10px, transparent 10px, transparent 20px);\n            transform: rotate(1deg);\n        }\n\n        .tape-top {\n            width: 80px;\n            height: 25px;\n            background: rgba(255, 255, 255, 0.7);\n            position: absolute;\n            top: -10px;\n            left: 50%;\n            transform: translateX(-50%) rotate(-1deg);\n            border-left: 1px dashed rgba(0, 0, 0, 0.1);\n            border-right: 1px dashed rgba(0, 0, 0, 0.1);\n        }\n\n        .time-big {\n            font-family: var(--font-title);\n            font-size: 1.6rem;\n            color: var(--ink-primary);\n            margin: 5px 0;\n            text-shadow: 1px 1px 0 #fff;\n        }\n\n        .time-desc {\n            font-family: var(--font-hand);\n            font-size: 1rem;\n            color: var(--ink-secondary);\n        }\n\n        /* ==================== 3. Layout Essentials ==================== */\n        .grid-layout {\n            display: grid;\n            grid-template-columns: repeat(12, 1fr);\n            gap: 20px;\n        }\n\n        .section-title {\n            font-family: var(--font-title);\n            font-size: 1.3rem;\n            margin-bottom: 10px;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n            break-after: avoid;\n        }\n\n        .section-title .doodle {\n            color: var(--accent-orange);\n        }\n\n        .chart-section {\n            grid-column: span 12;\n            background: #fff;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 12px;\n            padding: 15px 15px 15px 35px;\n            position: relative;\n            box-shadow: 3px 3px 0 rgba(0, 0, 0, 0.05);\n            break-inside: avoid;\n        }\n\n        .coil {\n            position: absolute;\n            left: 10px;\n            top: 15px;\n            bottom: 15px;\n            width: 8px;\n            background: repeating-linear-gradient(to bottom, #ccc 0, #ccc 2px, transparent 2px, transparent 12px);\n            border-left: 1px solid #999;\n        }\n\n        /* ==================== 4. Components ==================== */\n        /* Hand-drawn bar chart simulation */\n        .hand-chart-row {\n            display: flex;\n            align-items: center;\n            margin-bottom: 10px;\n        }\n\n        .chart-label {\n            width: 40px;\n            font-family: var(--font-hand);\n            font-size: 1rem;\n        }\n\n        .chart-bar-box {\n            flex: 1;\n            margin-left: 8px;\n        }\n\n        .crayon-bar {\n            height: 12px;\n            border-radius: 6px;\n            border: 1px solid var(--ink-primary);\n            background-image: url(\"data:image/svg+xml,%3Csvg width='4' height='4' viewBox='0 0 4 4' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M0 4L4 0' stroke='rgba(0,0,0,0.1)' stroke-width='1'/%3E%3C/svg%3E\");\n        }\n\n        /* Horizontal Chart Styles */\n        .chart-section-horizontal {\n            display: flex;\n            align-items: flex-end;\n            justify-content: space-between;\n            height: 150px;\n            padding: 10px 5px 2px 5px;\n            margin-top: 10px;\n            position: relative;\n            border-bottom: 1px solid var(--ink-secondary);\n        }\n\n        .chart-column {\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: flex-end;\n            height: 100%;\n            flex: 1;\n            margin: 0 2px;\n            position: relative;\n        }\n\n        .chart-bar-vertical {\n            width: 70%;\n            border-radius: 3px 3px 0 0;\n            min-height: 2px;\n            position: relative;\n            box-shadow: 1px 1px 0 rgba(0, 0, 0, 0.1);\n            transition: height 0.3s ease;\n        }\n\n        .chart-label-xaxis {\n            margin-top: 5px;\n            font-size: 0.7rem;\n            color: var(--ink-secondary);\n            font-family: var(--font-hand);\n            text-align: center;\n        }\n\n        .chart-value-top {\n            position: absolute;\n            top: -18px;\n            font-size: 0.65rem;\n            font-weight: bold;\n            color: var(--ink-secondary);\n            font-family: var(--font-hand);\n            width: 100%;\n            text-align: center;\n        }\n\n        .topic-section {\n            grid-column: span 12;\n            background: #fff;\n            padding: 20px 20px 20px 40px;\n            border: 1px solid #eee;\n            background-image: repeating-linear-gradient(transparent, transparent 29px, #e1f5fe 29px, #e1f5fe 30px);\n            line-height: 30px;\n            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.02);\n            position: relative;\n        }\n\n        .paper-holes {\n            position: absolute;\n            left: 10px;\n            top: 0;\n            bottom: 0;\n            width: 15px;\n            display: flex;\n            flex-direction: column;\n            justify-content: space-evenly;\n        }\n\n        .hole {\n            width: 10px;\n            height: 10px;\n            background: var(--bg-paper);\n            border-radius: 50%;\n            box-shadow: inset 1px 1px 2px rgba(0, 0, 0, 0.1);\n        }\n\n        .topic-item {\n            display: flex;\n            align-items: flex-start;\n            margin-bottom: 0;\n            padding-top: 4px;\n        }\n\n        .check-box {\n            width: 14px;\n            height: 14px;\n            border: 1px solid var(--ink-primary);\n            margin-right: 8px;\n            margin-top: 4px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            background: #fff;\n            flex-shrink: 0;\n        }\n\n        .check-tick {\n            width: 8px;\n            height: 8px;\n            background: var(--accent-orange);\n            clip-path: polygon(14% 44%, 0 65%, 50% 100%, 100% 16%, 80% 0%, 43% 62%);\n        }\n\n        .topic-content {\n            line-height: 1.4;\n            padding-top: 4px;\n            flex: 1;\n        }\n\n        .topic-title {\n            font-family: var(--font-title);\n            font-size: 1.15rem;\n            margin-right: 8px;\n            background: linear-gradient(transparent 60%, var(--color-pink) 60%);\n            display: inline-block;\n        }\n\n        .topic-detail {\n            font-family: var(--font-hand);\n            color: #666;\n            font-size: 1.1rem;\n            margin-top: 5px;\n        }\n\n        .user-section {\n            grid-column: span 12;\n            margin-top: 15px;\n        }\n\n        .masonry-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 15px;\n        }\n\n        .user-card {\n            background: #fffbf5;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 10px;\n            padding: 15px;\n            margin-bottom: 15px;\n            box-shadow: 5px 5px 0 rgba(0, 0, 0, 0.05);\n            position: relative;\n            display: flex;\n            flex-direction: column;\n            break-inside: avoid;\n        }\n\n        .card-tape {\n            position: absolute;\n            top: -8px;\n            left: 50%;\n            transform: translateX(-50%) rotate(-1deg);\n            width: 60px;\n            height: 16px;\n            background: rgba(255, 255, 255, 0.4);\n            background-color: var(--color-blue);\n            opacity: 0.7;\n            border-left: 1px dashed rgba(255, 255, 255, 0.3);\n            border-right: 1px dashed rgba(255, 255, 255, 0.3);\n            z-index: 2;\n        }\n\n        .user-card:nth-child(2n) .card-tape {\n            background-color: var(--color-pink);\n            transform: translateX(-50%) rotate(2deg);\n        }\n\n        .user-card:nth-child(3n) .card-tape {\n            background-color: var(--color-green);\n            transform: translateX(-50%) rotate(-0.5deg);\n        }\n\n        .user-header {\n            display: flex;\n            align-items: flex-start;\n            gap: 10px;\n            margin-bottom: 10px;\n            border-bottom: 1px dashed #f0f0f0;\n            padding-bottom: 10px;\n        }\n\n        .u-avatar {\n            width: 50px;\n            height: 50px;\n            border-radius: 50%;\n            border: 1.5px solid var(--ink-primary);\n            background: #eee;\n            flex-shrink: 0;\n            overflow: hidden;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #aaa;\n        }\n\n        .u-info {\n            flex: 1;\n            min-width: 0;\n            display: flex;\n            flex-direction: column;\n            gap: 4px;\n        }\n\n        .u-name {\n            font-family: var(--font-title);\n            font-size: 1.1rem;\n            line-height: 1.2;\n            word-break: break-all;\n            overflow-wrap: break-word;\n        }\n\n        .badges {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 6px;\n        }\n\n        .badge {\n            font-size: 0.75rem;\n            padding: 2px 6px;\n            border-radius: 4px;\n            font-family: var(--font-hand);\n            white-space: nowrap;\n            box-shadow: 1px 1px 0 rgba(0, 0, 0, 0.05);\n            display: flex;\n            align-items: center;\n        }\n\n        .badge.title {\n            background: var(--title-bg);\n            color: var(--title-text);\n            border: 1px solid var(--title-border);\n        }\n\n        .badge.mbti {\n            background: var(--mbti-bg);\n            color: var(--mbti-text);\n            border: 1px solid var(--mbti-border);\n            font-weight: bold;\n            letter-spacing: 0.5px;\n        }\n\n        .u-reason {\n            font-family: var(--font-hand);\n            font-size: 0.95rem;\n            color: #444;\n            line-height: 1.5;\n            background: #f8fbff;\n            border-left: 3px solid var(--color-blue);\n            padding: 10px 12px;\n            margin-top: 10px;\n            border-radius: 3px;\n            position: relative;\n            word-break: break-all;\n            overflow-wrap: break-word;\n        }\n\n        /* ==================== 5. Daily Echoes ==================== */\n        .quotes-section {\n            grid-column: span 12;\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n            margin-top: 15px;\n        }\n\n        .quote-wrapper {\n            display: flex;\n            flex-direction: column;\n            width: 100%;\n            max-width: 100%;\n            position: relative;\n            break-inside: avoid;\n            margin-bottom: 15px;\n        }\n\n        .q-flex-container {\n            display: flex;\n            gap: 8px;\n            align-items: flex-start;\n        }\n\n        .q-user-col {\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            flex-shrink: 0;\n            width: 40px;\n        }\n\n        .q-avatar-box {\n            position: relative;\n            margin-bottom: 4px;\n        }\n\n        .q-avatar {\n            width: 40px;\n            height: 40px;\n            border-radius: 50%;\n            border: 1.5px solid #fff;\n            background: #fff;\n            object-fit: cover;\n            box-shadow: 1px 1px 0 rgba(0, 0, 0, 0.1);\n        }\n\n        /* Left/Odd: Blue Shadow */\n        .quote-wrapper:nth-child(odd) .q-avatar {\n            box-shadow: 0 0 0 1.5px var(--color-blue);\n        }\n\n        /* Right/Even: Orange Shadow */\n        .quote-wrapper:nth-child(even) .q-avatar {\n            box-shadow: 0 0 0 1.5px var(--accent-orange);\n        }\n\n        .q-content-col {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            min-width: 0;\n            align-items: flex-start;\n        }\n\n        .q-sender-name {\n            font-family: 'Long Cang', cursive;\n            font-size: 1rem;\n            color: var(--ink-primary);\n            margin-bottom: 1px;\n            margin-left: 6px;\n            line-height: 1.2;\n            position: relative;\n            display: inline-block;\n        }\n\n        /* Underline Element */\n        .q-sender-name::after {\n            content: \"\";\n            display: block;\n            width: 100%;\n            height: 2px;\n            background: var(--color-blue);\n            opacity: 0.4;\n            border-radius: 1px;\n            margin-top: -4px;\n        }\n\n        /* Right-aligned layout for even items */\n        .quote-wrapper:nth-child(even) .q-flex-container {\n            flex-direction: row-reverse;\n        }\n\n        .quote-wrapper:nth-child(even) .q-content-col {\n            align-items: flex-end;\n        }\n\n        .quote-wrapper:nth-child(even) .q-sender-name {\n            margin-left: 0;\n            margin-right: 10px;\n            text-align: right;\n        }\n\n        .quote-wrapper:nth-child(even) .q-sender-name::after {\n            background: var(--accent-orange);\n        }\n\n        .quote-wrapper:nth-child(odd) {\n            align-self: flex-start;\n        }\n\n        .quote-wrapper:nth-child(even) {\n            align-self: flex-end;\n            align-items: flex-end;\n        }\n\n        .q-bubble {\n            background: #fff;\n            border: 1.5px solid var(--ink-primary);\n            padding: 10px 15px;\n            border-radius: 12px;\n            box-shadow: 3px 3px 0 var(--color-blue);\n            position: relative;\n            z-index: 2;\n            width: fit-content;\n            max-width: 90%;\n        }\n\n        .quote-wrapper:nth-child(odd) .q-bubble {\n            border-top-left-radius: 4px;\n        }\n\n        .quote-wrapper:nth-child(even) .q-bubble {\n            border-top-right-radius: 4px;\n            border-bottom-right-radius: 12px;\n            background: var(--color-yellow);\n            box-shadow: -3px 3px 0 var(--color-pink);\n            text-align: right;\n            border-bottom-left-radius: 12px;\n        }\n\n        .q-content {\n            font-family: var(--font-title);\n            font-size: 1.1rem;\n            line-height: 1.3;\n            margin-bottom: 4px;\n            position: relative;\n        }\n\n        .q-quote-mark {\n            display: none;\n        }\n\n        .q-analysis-note {\n            background: #fffde7;\n            padding: 8px 12px;\n            font-size: 0.85rem;\n            color: #666;\n            width: fit-content;\n            max-width: 100%;\n            margin-top: -4px;\n            box-shadow: 1px 1px 3px rgba(0, 0, 0, 0.1);\n            border: 1px solid #ddd;\n            position: relative;\n            z-index: 1;\n            font-family: var(--font-body);\n            line-height: 1.4;\n            border-radius: 0 0 8px 8px;\n        }\n\n        .quote-wrapper:nth-child(odd) .q-analysis-note {\n            transform: rotate(-0.5deg) translateX(8px);\n            border-radius: 0 0 8px 8px;\n        }\n\n        .quote-wrapper:nth-child(even) .q-analysis-note {\n            transform: rotate(0.5deg) translateX(-8px);\n            text-align: left;\n            background: #f3e5f5;\n            border-radius: 0 0 8px 8px;\n        }\n\n        .note-label {\n            font-weight: bold;\n            color: var(--accent-orange);\n            display: block;\n            margin-bottom: 3px;\n            font-family: var(--font-title);\n        }\n\n        .quality-section {\n            grid-column: span 12;\n            margin-top: 15px;\n            background: #fff;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 3px 3px 0 rgba(0, 0, 0, 0.05);\n        }\n\n        /* ==================== 5. Footer Stickers ==================== */\n        .footer {\n            margin-top: 30px;\n            display: flex;\n            flex-direction: row;\n            justify-content: space-between;\n            gap: 15px;\n            padding: 20px 0;\n            border-top: 1.5px dashed #ccc;\n            break-inside: avoid;\n        }\n\n        .footer-card {\n            flex: 1;\n            background: #fff;\n            border: 1.5px solid var(--ink-primary);\n            border-radius: 8px;\n            padding: 10px;\n            text-align: center;\n            font-family: var(--font-hand);\n            position: relative;\n            box-shadow: 3px 3px 0 rgba(0, 0, 0, 0.05);\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            min-width: 0;\n        }\n\n        .footer-card .card-tape {\n            top: -6px;\n            width: 40px;\n            height: 12px;\n            background: rgba(0, 0, 0, 0.05);\n            border: none;\n        }\n\n        .footer-card-title {\n            font-weight: bold;\n            font-size: 1rem;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            gap: 5px;\n        }\n\n        .footer-card-content {\n            font-size: 0.85rem;\n            color: #666;\n        }\n\n        .footer-card a {\n            color: inherit;\n            text-decoration: underline;\n            word-break: break-all;\n            overflow-wrap: anywhere;\n            font-size: 0.72rem;\n            line-height: 1.2;\n            display: inline-block;\n            margin-top: 2px;\n        }\n\n        .info-card { border-color: var(--accent-orange); box-shadow: 3px 3px 0 var(--color-pink); }\n        .info-card .card-tape { background: var(--color-pink); opacity: 0.6; }\n\n        .repo-card { border-color: var(--color-blue); box-shadow: 3px 3px 0 var(--color-blue); }\n        .repo-card .card-tape { background: var(--color-blue); opacity: 0.6; }\n\n        .stats-card { border-color: var(--color-purple); box-shadow: 3px 3px 0 var(--color-purple); }\n        .stats-card .card-tape { background: var(--color-purple); opacity: 0.6; }\n\n        .avoid-break {\n            break-inside: avoid;\n            page-break-inside: avoid !important;\n        }\n\n        @media print {\n            body {\n                padding: 0;\n                background: white;\n            }\n\n            .container {\n                width: 100%;\n                max-width: none;\n                border: none;\n                padding: 10mm;\n            }\n            .container::before {\n                display: none;\n            }\n        }\n    </style>\n</head>\n\n<body>\n    <div class=\"container\">\n\n        <!-- 1. 头部 -->\n        <div class=\"header\">\n            <div class=\"title-sticker\">\n                <div class=\"tape\"></div>\n                <h1>五彩斑斓的一天，来看看群里发生了什么吧！</h1>\n                <div class=\"date-badge\">";
      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "current_date"), env.opts.autoescape);
      output += "</div>\n            </div>\n        </div>\n\n        <!-- 2. 统计邮票和活跃时段 -->\n        <div class=\"stats-wrapper\">\n            <!-- Left: Stats Grid (2x2) -->\n            <div class=\"stats-grid\">\n                <!-- Chat Icon -->\n                <div class=\"stamp\">\n                    <div class=\"stamp-inner\">\n                        <svg class=\"doodle\" viewBox=\"0 0 24 24\" style=\"color: var(--accent-orange);\">\n                            <path\n                                d=\"M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm0 14H6l-2 2V4h16v12z\" />\n                        </svg>\n                        <div class=\"stamp-num\">";
      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "message_count"), env.opts.autoescape);
      output += "</div>\n                        <div class=\"stamp-label\">消息总数</div>\n                    </div>\n                </div>\n                <!-- Users Icon -->\n                <div class=\"stamp\">\n                    <div class=\"stamp-inner\">\n                        <svg class=\"doodle\" viewBox=\"0 0 24 24\" style=\"color: var(--color-green);\">\n                            <path\n                                d=\"M16 11c1.66 0 2.99-1.34 2.99-3S17.66 5 16 5c-1.66 0-3 1.34-3 3s1.34 3 3 3zm-8 0c1.66 0 2.99-1.34 2.99-3S9.66 5 8 5C6.34 5 5 6.34 5 8s1.34 3 3 3zm0 2c-2.33 0-7 1.17-7 3.5V19h14v-2.5c0-2.33-4.67-3.5-7-3.5zm8 0c-.29 0-.62.02-.97.05 1.16.84 1.97 1.97 1.97 3.45V19h6v-2.5c0-2.33-4.67-3.5-7-3.5z\" />\n                        </svg>\n                        <div class=\"stamp-num\">";
      output += runtime.suppressValue(runtime.contextOrFrameLookup(context, frame, "participant_count"), env.opts.autoescape);
